import{_ as e,o as d,c as a,ag as r}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"Configuration Reference","description":"All Krado One environment variables — core, database, frontend, integrations, and cloud providers.","frontmatter":{"title":"Configuration Reference","description":"All Krado One environment variables — core, database, frontend, integrations, and cloud providers."},"headers":[],"relativePath":"reference/configuration.md","filePath":"reference/configuration.md"}'),o={name:"reference/configuration.md"};function c(n,t,i,h,s,l){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="configuration-reference" tabindex="-1">Configuration reference <a class="header-anchor" href="#configuration-reference" aria-label="Permalink to &quot;Configuration reference&quot;">​</a></h1><p>All configuration is done via environment variables. Copy <code>.env.example</code> to <code>.env</code> and edit before starting.</p><p>Variables set via <strong>Portal Config → Integrations</strong> are stored in the database and take precedence over env vars after first boot.</p><hr><h2 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>PORT</code></td><td><code>8080</code></td><td>Backend API port</td></tr><tr><td><code>GIN_MODE</code></td><td><code>debug</code></td><td>Set to <code>release</code> in production</td></tr><tr><td><code>JWT_SECRET</code></td><td>random</td><td><strong>Required in production.</strong> 32+ random characters. If unset, sessions are lost on restart</td></tr><tr><td><code>APP_EDITION</code></td><td><code>community</code></td><td>Default tier when no license key is present: <code>community</code>, <code>pro</code>, or <code>enterprise</code>.</td></tr><tr><td><code>EDITION_UPGRADE_URL</code></td><td>—</td><td>URL shown in upgrade prompts</td></tr><tr><td><code>LICENSE_KEY</code></td><td>—</td><td>Pro/Enterprise license key. Validated offline (no external service). Also managed via Portal Config → License.</td></tr><tr><td><code>LICENSE_KEY_FILE</code></td><td>—</td><td>Path to a file containing the license key (alternative to <code>LICENSE_KEY</code>).</td></tr><tr><td><code>DEVX_DATA_DIR</code></td><td><code>../data</code></td><td>Directory for <code>license.key</code> and <code>tasks.db</code>.</td></tr></tbody></table><hr><h2 id="database" tabindex="-1">Database <a class="header-anchor" href="#database" aria-label="Permalink to &quot;Database&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>DB_DRIVER</code></td><td><code>sqlite</code></td><td><code>sqlite</code> or <code>postgres</code></td></tr><tr><td><code>DB_PATH</code></td><td><code>../data/tasks.db</code></td><td>SQLite file path</td></tr><tr><td><code>DB_DSN</code></td><td>—</td><td>PostgreSQL DSN: <code>host=... user=... password=... dbname=... port=5432 sslmode=disable TimeZone=UTC</code></td></tr></tbody></table><hr><h2 id="frontend" tabindex="-1">Frontend <a class="header-anchor" href="#frontend" aria-label="Permalink to &quot;Frontend&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>VITE_API_URL</code></td><td><code>http://localhost:8080/api</code></td><td>Backend API URL (browser-visible)</td></tr><tr><td><code>VITE_N8N_URL</code></td><td>—</td><td>n8n URL for embedded workflow UI</td></tr></tbody></table><p>Set <code>VITE_API_URL</code> to your public backend URL before building the frontend image.</p><hr><h2 id="jira" tabindex="-1">JIRA <a class="header-anchor" href="#jira" aria-label="Permalink to &quot;JIRA&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>JIRA_URL</code></td><td>Atlassian base URL</td></tr><tr><td><code>JIRA_EMAIL</code></td><td>Service account email</td></tr><tr><td><code>JIRA_API_TOKEN</code></td><td>Atlassian API token</td></tr></tbody></table><hr><h2 id="slack" tabindex="-1">Slack <a class="header-anchor" href="#slack" aria-label="Permalink to &quot;Slack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>SLACK_BOT_TOKEN</code></td><td><code>xoxb-...</code> bot token</td></tr><tr><td><code>SLACK_WEBHOOK_URL</code></td><td>Incoming webhook URL</td></tr><tr><td><code>SLACK_SCAN_CHANNEL_IDS</code></td><td>Comma-separated channel IDs to scan</td></tr><tr><td><code>SLACK_MENTION_USER_ID</code></td><td>User ID to @mention</td></tr></tbody></table><hr><h2 id="n8n" tabindex="-1">n8n <a class="header-anchor" href="#n8n" aria-label="Permalink to &quot;n8n&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>N8N_URL</code></td><td>n8n base URL</td></tr><tr><td><code>N8N_API_KEY</code></td><td>n8n API key</td></tr></tbody></table><hr><h2 id="openai" tabindex="-1">OpenAI <a class="header-anchor" href="#openai" aria-label="Permalink to &quot;OpenAI&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>OPENAI_API_KEY</code></td><td>OpenAI API key</td></tr><tr><td><code>OPENAI_MODEL</code></td><td>Model ID (default: <code>gpt-4o</code>)</td></tr><tr><td><code>OPENAI_SYSTEM_PROMPT</code></td><td>Override assistant system prompt</td></tr></tbody></table><hr><h2 id="github" tabindex="-1">GitHub <a class="header-anchor" href="#github" aria-label="Permalink to &quot;GitHub&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>GITHUB_ORG</code></td><td>GitHub organization name</td></tr><tr><td><code>GITHUB_PAT</code></td><td>PAT with <code>repo</code> + <code>read:org</code> scopes</td></tr></tbody></table><hr><h2 id="terraform-cloud" tabindex="-1">Terraform Cloud <a class="header-anchor" href="#terraform-cloud" aria-label="Permalink to &quot;Terraform Cloud&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>TERRAFORM_ORG</code></td><td>Terraform Cloud organization</td></tr><tr><td><code>TERRAFORM_API_TOKEN</code></td><td>Terraform Cloud API token</td></tr><tr><td><code>TERRAFORM_WORKSPACE_PREFIX</code></td><td>Filter workspaces by prefix</td></tr></tbody></table><hr><h2 id="argocd" tabindex="-1">ArgoCD <a class="header-anchor" href="#argocd" aria-label="Permalink to &quot;ArgoCD&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>ARGOCD_URL</code></td><td>ArgoCD server URL</td></tr><tr><td><code>ARGOCD_API_TOKEN</code></td><td>ArgoCD API token</td></tr></tbody></table><hr><h2 id="pagerduty" tabindex="-1">PagerDuty <a class="header-anchor" href="#pagerduty" aria-label="Permalink to &quot;PagerDuty&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>PAGERDUTY_API_KEY</code></td><td>PagerDuty REST API key</td></tr></tbody></table><hr><h2 id="prometheus" tabindex="-1">Prometheus <a class="header-anchor" href="#prometheus" aria-label="Permalink to &quot;Prometheus&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>PROMETHEUS_URL</code></td><td>Prometheus base URL</td></tr></tbody></table><hr><h2 id="aws" tabindex="-1">AWS <a class="header-anchor" href="#aws" aria-label="Permalink to &quot;AWS&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>AWS_ACCESS_KEY_ID</code></td><td>AWS access key</td></tr><tr><td><code>AWS_SECRET_ACCESS_KEY</code></td><td>AWS secret key</td></tr><tr><td><code>AWS_REGION</code></td><td>Primary region, e.g. <code>us-east-1</code></td></tr></tbody></table><hr><h2 id="gcp" tabindex="-1">GCP <a class="header-anchor" href="#gcp" aria-label="Permalink to &quot;GCP&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>GCP_PROJECT_ID</code></td><td>GCP project ID</td></tr><tr><td><code>GCP_SERVICE_ACCOUNT_JSON</code></td><td>Service account JSON (base64 or path)</td></tr></tbody></table><hr><h2 id="azure" tabindex="-1">Azure <a class="header-anchor" href="#azure" aria-label="Permalink to &quot;Azure&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>AZURE_TENANT_ID</code></td><td>Azure tenant ID</td></tr><tr><td><code>AZURE_CLIENT_ID</code></td><td>App registration client ID</td></tr><tr><td><code>AZURE_CLIENT_SECRET</code></td><td>App registration client secret</td></tr><tr><td><code>AZURE_SUBSCRIPTION_ID</code></td><td>Subscription to inventory</td></tr></tbody></table><hr><h2 id="google-calendar" tabindex="-1">Google Calendar <a class="header-anchor" href="#google-calendar" aria-label="Permalink to &quot;Google Calendar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>GOOGLE_CALENDAR_ID</code></td><td>Calendar ID for maintenance events</td></tr><tr><td><code>GOOGLE_SERVICE_ACCOUNT_JSON</code></td><td>Service account JSON (base64 or path)</td></tr></tbody></table><hr><h2 id="smtp" tabindex="-1">SMTP <a class="header-anchor" href="#smtp" aria-label="Permalink to &quot;SMTP&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>SMTP_HOST</code></td><td>—</td><td>SMTP server hostname</td></tr><tr><td><code>SMTP_PORT</code></td><td><code>587</code></td><td>SMTP port</td></tr><tr><td><code>SMTP_USER</code></td><td>—</td><td>SMTP username</td></tr><tr><td><code>SMTP_PASSWORD</code></td><td>—</td><td>SMTP password</td></tr><tr><td><code>SMTP_FROM</code></td><td><code>noreply@krado.local</code></td><td>From address</td></tr></tbody></table><hr><h2 id="generating-the-openapi-spec" tabindex="-1">Generating the OpenAPI spec <a class="header-anchor" href="#generating-the-openapi-spec" aria-label="Permalink to &quot;Generating the OpenAPI spec&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/generate-openapi.mjs</span></span></code></pre></div><p>Output: <code>static/openapi/openapi.json</code> — used by the interactive API explorer at <code>/api-explorer</code>.</p>',59)])])}const u=e(o,[["render",c]]);export{p as __pageData,u as default};
